import { Racquet, PCACoordinates } from '../types';

export interface PCAResult {
  coordinates: PCACoordinates[];
  variance: number[];
  total_variance: number;
  feature_importance: Record<string, number>;
}

export interface PCAOptions {
  features: (keyof Racquet)[];
  normalize?: boolean;
  dimensions?: 2 | 3;
}

export class PCACalculator {
  private features: (keyof Racquet)[];
  private normalize: boolean;
  private dimensions: 2 | 3;

  constructor(options: PCAOptions) {
    this.features = options.features;
    this.normalize = options.normalize ?? true;
    this.dimensions = options.dimensions ?? 3;
  }

  public calculatePCA(racquets: Racquet[]): PCAResult {
    const validRacquets = this.filterValidRacquets(racquets);

    if (validRacquets.length === 0) {
      throw new Error('No valid racquets found for PCA calculation');
    }

    const matrix = this.buildFeatureMatrix(validRacquets);
    const normalizedMatrix = this.normalize ? this.normalizeMatrix(matrix) : matrix;
    const covarianceMatrix = this.calculateCovarianceMatrix(normalizedMatrix);
    const eigenDecomposition = this.calculateEigenDecomposition(covarianceMatrix);

    const coordinates = this.projectToComponents(normalizedMatrix, eigenDecomposition.vectors);
    const variance = eigenDecomposition.values.slice(0, this.dimensions);
    const total_variance = variance.reduce((sum, val) => sum + val, 0);

    return {
      coordinates: coordinates.map(coord => ({
        x: coord[0],
        y: coord[1],
        z: this.dimensions === 3 ? coord[2] : undefined
      })),
      variance,
      total_variance,
      feature_importance: this.calculateFeatureImportance(eigenDecomposition.vectors)
    };
  }

  private filterValidRacquets(racquets: Racquet[]): Racquet[] {
    return racquets.filter(racquet => {
      return this.features.every(feature => {
        const value = racquet[feature];
        return value !== null && value !== undefined && typeof value === 'number' && !isNaN(value);
      });
    });
  }

  private buildFeatureMatrix(racquets: Racquet[]): number[][] {
    return racquets.map(racquet => 
      this.features.map(feature => Number(racquet[feature]))
    );
  }

  private normalizeMatrix(matrix: number[][]): number[][] {
    const means = this.calculateMeans(matrix);
    const stds = this.calculateStandardDeviations(matrix, means);

    return matrix.map(row => 
      row.map((value, index) => 
        stds[index] === 0 ? 0 : (value - means[index]) / stds[index]
      )
    );
  }

  private calculateMeans(matrix: number[][]): number[] {
    const featureCount = matrix[0].length;
    const means: number[] = new Array(featureCount).fill(0);

    for (let i = 0; i < featureCount; i++) {
      for (let j = 0; j < matrix.length; j++) {
        means[i] += matrix[j][i];
      }
      means[i] /= matrix.length;
    }

    return means;
  }

  private calculateStandardDeviations(matrix: number[][], means: number[]): number[] {
    const featureCount = matrix[0].length;
    const stds: number[] = new Array(featureCount).fill(0);

    for (let i = 0; i < featureCount; i++) {
      for (let j = 0; j < matrix.length; j++) {
        stds[i] += Math.pow(matrix[j][i] - means[i], 2);
      }
      stds[i] = Math.sqrt(stds[i] / (matrix.length - 1));
    }

    return stds;
  }

  private calculateCovarianceMatrix(matrix: number[][]): number[][] {
    const featureCount = matrix[0].length;
    const covariance: number[][] = Array(featureCount).fill(null).map(() => Array(featureCount).fill(0));

    for (let i = 0; i < featureCount; i++) {
      for (let j = 0; j < featureCount; j++) {
        let sum = 0;
        for (let k = 0; k < matrix.length; k++) {
          sum += matrix[k][i] * matrix[k][j];
        }
        covariance[i][j] = sum / (matrix.length - 1);
      }
    }

    return covariance;
  }

  private calculateEigenDecomposition(matrix: number[][]): { values: number[]; vectors: number[][] } {
    const size = matrix.length;
    const eigenValues: number[] = [];
    const eigenVectors: number[][] = [];

    // Using power iteration method for simplicity
    // In a production environment, you might want to use a more robust library
    const maxIterations = 1000;
    const tolerance = 1e-10;

    for (let component = 0; component < Math.min(size, this.dimensions); component++) {
      let vector: number[] = new Array(size).fill(0).map(() => Math.random());
      let eigenValue = 0;

      // Power iteration
      for (let iteration = 0; iteration < maxIterations; iteration++) {
        const newVector = this.multiplyMatrixVector(matrix, vector);
        const norm = this.vectorNorm(newVector);

        if (norm === 0) break;

        const normalizedVector = newVector.map(v => v / norm);
        const newEigenValue = this.dotProduct(normalizedVector, this.multiplyMatrixVector(matrix, normalizedVector));

        if (Math.abs(newEigenValue - eigenValue) < tolerance) {
          break;
        }

        eigenValue = newEigenValue;
        vector = normalizedVector;
      }

      eigenValues.push(eigenValue);
      eigenVectors.push(vector);

      // Deflate matrix for next component
      if (component < this.dimensions - 1) {
        matrix = this.deflateMatrix(matrix, eigenValue, vector);
      }
    }

    return { values: eigenValues, vectors: eigenVectors };
  }

  private multiplyMatrixVector(matrix: number[][], vector: number[]): number[] {
    return matrix.map(row => 
      row.reduce((sum, val, index) => sum + val * vector[index], 0)
    );
  }

  private vectorNorm(vector: number[]): number {
    return Math.sqrt(vector.reduce((sum, val) => sum + val * val, 0));
  }

  private dotProduct(a: number[], b: number[]): number {
    return a.reduce((sum, val, index) => sum + val * b[index], 0);
  }

  private deflateMatrix(matrix: number[][], eigenValue: number, eigenVector: number[]): number[][] {
    const size = matrix.length;
    const deflated: number[][] = Array(size).fill(null).map(() => Array(size).fill(0));

    for (let i = 0; i < size; i++) {
      for (let j = 0; j < size; j++) {
        deflated[i][j] = matrix[i][j] - eigenValue * eigenVector[i] * eigenVector[j];
      }
    }

    return deflated;
  }

  private projectToComponents(matrix: number[][], eigenVectors: number[][]): number[][] {
    return matrix.map(row => 
      eigenVectors.map(vector => 
        this.dotProduct(row, vector)
      )
    );
  }

  private calculateFeatureImportance(eigenVectors: number[][]): Record<string, number> {
    const importance: Record<string, number> = {};

    this.features.forEach((feature, index) => {
      let totalContribution = 0;
      for (let component = 0; component < eigenVectors.length; component++) {
        totalContribution += Math.abs(eigenVectors[component][index]);
      }
      importance[String(feature)] = totalContribution / eigenVectors.length;
    });

    return importance;
  }
}

export function calculateRacquetPCA(racquets: Racquet[], options?: Partial<PCAOptions>): PCAResult {
  const defaultFeatures: (keyof Racquet)[] = [
    'weight_oz',
    'head_size_sq_in', 
    'swingweight',
    'flex',
    'power_avg',
    'control_avg',
    'comfort_avg',
    'maneuverability_avg',
    'stability_avg'
  ];

  const calculator = new PCACalculator({
    features: options?.features ?? defaultFeatures,
    normalize: options?.normalize ?? true,
    dimensions: options?.dimensions ?? 3
  });

  return calculator.calculatePCA(racquets);
}

