import { Racquet } from '@/lib/types';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Select } from '@/components/ui/Select';
import { LoadingSpinner } from '@/components/ui/LoadingSpinner';
import * as THREE from 'three';

interface RacquetVisualization3DProps {
  racquets: Racquet[];
  className?: string;
}

type ColorByOption = {
  value: keyof Racquet;
  label: string;
  description: string;
};

const colorByOptions: ColorByOption[] = [
  { value: 'brand', label: 'Brand', description: 'Color by racquet brand' },
  { value: 'weight_oz', label: 'Weight', description: 'Color by weight in ounces' },
  { value: 'head_size_sq_in', label: 'Head Size', description: 'Color by head size' },
  { value: 'power_avg', label: 'Power Rating', description: 'Color by power rating' },
  { value: 'control_avg', label: 'Control Rating', description: 'Color by control rating' },
  { value: 'overall_avg', label: 'Overall Rating', description: 'Color by overall rating' },
];

const presetViews = [
  {
    id: 'performance',
    name: 'Performance Space',
    description: 'PCA based on performance ratings',
    features: ['power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg', 'stability_avg'] as (keyof Racquet)[],
    cameraPosition: [15, 15, 15] as [number, number, number]
  },
  {
    id: 'physical',
    name: 'Physical Space', 
    description: 'PCA based on physical characteristics',
    features: ['weight_oz', 'head_size_sq_in', 'swingweight', 'flex'] as (keyof Racquet)[],
    cameraPosition: [12, 8, 12] as [number, number, number]
  },
  {
    id: 'combined',
    name: 'Combined Space',
    description: 'PCA based on all characteristics',
    features: ['weight_oz', 'head_size_sq_in', 'swingweight', 'flex', 'power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg', 'stability_avg'] as (keyof Racquet)[],
    cameraPosition: [10, 10, 10] as [number, number, number]
  },
  {
    id: 'playability',
    name: 'Playability Space',
    description: 'PCA based on shot-specific ratings',
    features: ['serves_avg', 'returns_avg', 'groundstrokes_avg', 'volleys_avg', 'slice_avg', 'topspin_avg'] as (keyof Racquet)[],
    cameraPosition: [8, 12, 8] as [number, number, number]
  }
];

export function RacquetVisualization3D({ racquets, className = '' }: RacquetVisualization3DProps) {
  const [selectedRacquet, setSelectedRacquet] = useState<string | null>(null);
  const [hoveredRacquet, setHoveredRacquet] = useState<string | null>(null);
  const [colorBy, setColorBy] = useState<keyof Racquet>('brand');
  const [currentView, setCurrentView] = useState(presetViews[0]);
  const [isCalculating, setIsCalculating] = useState(false);
  const [cameraPosition, setCameraPosition] = useState<[number, number, number]>([10, 10, 10]);
  const [cameraTarget, setCameraTarget] = useState<[number, number, number]>([0, 0, 0]);

