'use client';

import { useRef, useMemo, useState, useCallback } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Html } from '@react-three/drei';
import { Racquet, PCACoordinates } from '@/lib/types';
import * as THREE from 'three';

interface RacquetPoint3DProps {
  racquet: Racquet;
  position: PCACoordinates;
  isSelected?: boolean;
  isHovered?: boolean;
  onClick?: (racquet: Racquet) => void;
  onHover?: (racquet: Racquet | null) => void;
  scale?: number;
  color?: string;
}

function RacquetPoint3D({
  racquet,
  position,
  isSelected = false,
  isHovered = false,
  onClick,
  onHover,
  scale = 1,
  color = '#3b82f6'
}: RacquetPoint3DProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const [hovered, setHovered] = useState(false);

  const pointColor = useMemo(() => {
    if (isSelected) return '#ef4444'; // Red for selected
    if (isHovered || hovered) return '#f59e0b'; // Yellow for hovered
    return color;
  }, [isSelected, isHovered, hovered, color]);

  const pointSize = useMemo(() => {
    const baseSize = 0.1 * scale;
    if (isSelected) return baseSize * 1.5;
    if (isHovered || hovered) return baseSize * 1.3;
    return baseSize;
  }, [isSelected, isHovered, hovered, scale]);

  useFrame((state) => {
    if (meshRef.current) {
      // Subtle animation for selected/hovered points
      if (isSelected || isHovered || hovered) {
        const time = state.clock.getElapsedTime();
        meshRef.current.scale.setScalar(pointSize * (1 + 0.1 * Math.sin(time * 3)));
      } else {
        meshRef.current.scale.setScalar(pointSize);
      }
    }
  });

  const handleClick = useCallback((event: THREE.Event) => {
    event.stopPropagation();
    onClick?.(racquet);
  }, [onClick, racquet]);

  const handlePointerEnter = useCallback((event: THREE.Event) => {
    event.stopPropagation();
    setHovered(true);
    onHover?.(racquet);
  }, [onHover, racquet]);

  const handlePointerLeave = useCallback((event: THREE.Event) => {
    event.stopPropagation();
    setHovered(false);
    onHover?.(null);
  }, [onHover]);

  return (
    <group position={[position.x, position.y, position.z || 0]}>
      <mesh
        ref={meshRef}
        onClick={handleClick}
        onPointerEnter={handlePointerEnter}
        onPointerLeave={handlePointerLeave}
      >
        <sphereGeometry args={[1, 16, 16]} />
        <meshStandardMaterial
          color={pointColor}
          transparent
          opacity={0.8}
          roughness={0.4}
          metalness={0.2}
        />
      </mesh>

      {/* Label for hovered/selected points */}
      {(isHovered || hovered || isSelected) && (
        <Html
          position={[0, pointSize * 15, 0]}
          center
          style={{
            backgroundColor: 'rgba(0, 0, 0, 0.8)',
            color: 'white',
            padding: '4px 8px',
            borderRadius: '4px',
            fontSize: '12px',
            whiteSpace: 'nowrap',
            pointerEvents: 'none',
            userSelect: 'none'
          }}
        >
          {racquet.model} ({racquet.brand})
        </Html>
      )}
    </group>
  );
}

interface RacquetPoints3DProps {
  racquets: Racquet[];
  positions: PCACoordinates[];
  selectedRacquet?: string | null;
  hoveredRacquet?: string | null;
  onRacquetClick?: (racquet: Racquet) => void;
  onRacquetHover?: (racquet: Racquet | null) => void;
  colorBy?: keyof Racquet;
  scale?: number;
}

export function RacquetPoints3D({
  racquets,
  positions,
  selectedRacquet,
  hoveredRacquet,
  onRacquetClick,
  onRacquetHover,
  colorBy = 'brand',
  scale = 1
}: RacquetPoints3DProps) {

  // Generate colors based on colorBy property
  const colorMap = useMemo(() => {
    const uniqueValues = Array.from(new Set(racquets.map(r => r[colorBy])));
    const colors = [
      '#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6',
      '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1'
    ];

    const map = new Map<unknown, string>();
    uniqueValues.forEach((value, index) => {
      map.set(value, colors[index % colors.length]);
    });

    return map;
  }, [racquets, colorBy]);

  // Calculate bounds for scaling
  const bounds = useMemo(() => {
    if (positions.length === 0) return { min: -1, max: 1 };

    const allValues = positions.flatMap(p => [p.x, p.y, p.z || 0]);
    const min = Math.min(...allValues);
    const max = Math.max(...allValues);
    const range = max - min;

    return { min, max, range };
  }, [positions]);

  // Scale positions to fit in scene
  const scaledPositions = useMemo(() => {
    if (bounds.range === 0) return positions;

    const scaleMultiplier = 8; // Fit within -8 to 8 range

    return positions.map(pos => ({
      x: ((pos.x - bounds.min) / bounds.range - 0.5) * scaleMultiplier,
      y: ((pos.y - bounds.min) / bounds.range - 0.5) * scaleMultiplier,
      z: pos.z ? ((pos.z - bounds.min) / bounds.range - 0.5) * scaleMultiplier : 0
    }));
  }, [positions, bounds]);

  const handleRacquetClick = useCallback((racquet: Racquet) => {
    onRacquetClick?.(racquet);
  }, [onRacquetClick]);

  const handleRacquetHover = useCallback((racquet: Racquet | null) => {
    onRacquetHover?.(racquet);
  }, [onRacquetHover]);

  return (
    <group>
      {racquets.map((racquet, index) => {
        if (index >= scaledPositions.length) return null;

        const position = scaledPositions[index];
        const color = colorMap.get(racquet[colorBy]) || '#3b82f6';

        return (
          <RacquetPoint3D
            key={racquet.id}
            racquet={racquet}
            position={position}
            isSelected={selectedRacquet === racquet.id}
            isHovered={hoveredRacquet === racquet.id}
            onClick={handleRacquetClick}
            onHover={handleRacquetHover}
            scale={scale}
            color={color}
          />
        );
      })}
    </group>
  );
}

