'use client';

import React, { useState, useMemo, useCallback } from 'react';
import { ThreeScene } from './ThreeScene';
import { RacquetPoints3D } from './RacquetPoints3D';
import { calculateRacquetPCA } from '@/lib/utils/pca-calculator';
import { Racquet } from '@/lib/types';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Select } from '@/components/ui/Select';
import { LoadingSpinner } from '@/components/ui/LoadingSpinner';
import * as THREE from 'three';

interface RacquetVisualization3DProps {
  racquets: Racquet[];
  className?: string;
}

type ColorByOption = {
  value: keyof Racquet;
  label: string;
  description: string;
};

const colorByOptions: ColorByOption[] = [
  { value: 'brand', label: 'Brand', description: 'Color by racquet brand' },
  { value: 'weight_oz', label: 'Weight', description: 'Color by weight in ounces' },
  { value: 'head_size_sq_in', label: 'Head Size', description: 'Color by head size' },
  { value: 'power_avg', label: 'Power Rating', description: 'Color by power rating' },
  { value: 'control_avg', label: 'Control Rating', description: 'Color by control rating' },
  { value: 'overall_avg', label: 'Overall Rating', description: 'Color by overall rating' },
];

const presetViews = [
  {
    id: 'performance',
    name: 'Performance Space',
    description: 'PCA based on performance ratings',
    features: ['power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg', 'stability_avg'] as (keyof Racquet)[],
    cameraPosition: [15, 15, 15] as [number, number, number]
  },
  {
    id: 'physical',
    name: 'Physical Space', 
    description: 'PCA based on physical characteristics',
    features: ['weight_oz', 'head_size_sq_in', 'swingweight', 'flex'] as (keyof Racquet)[],
    cameraPosition: [12, 8, 12] as [number, number, number]
  },
  {
    id: 'combined',
    name: 'Combined Space',
    description: 'PCA based on all characteristics',
    features: ['weight_oz', 'head_size_sq_in', 'swingweight', 'flex', 'power_avg', 'control_avg', 'comfort_avg', 'maneuverability_avg', 'stability_avg'] as (keyof Racquet)[],
    cameraPosition: [10, 10, 10] as [number, number, number]
  },
  {
    id: 'playability',
    name: 'Playability Space',
    description: 'PCA based on shot-specific ratings',
    features: ['serves_avg', 'returns_avg', 'groundstrokes_avg', 'volleys_avg', 'slice_avg', 'topspin_avg'] as (keyof Racquet)[],
    cameraPosition: [8, 12, 8] as [number, number, number]
  }
];

export function RacquetVisualization3D({ racquets, className = '' }: RacquetVisualization3DProps) {
  const [selectedRacquet, setSelectedRacquet] = useState<string | null>(null);
  const [hoveredRacquet, setHoveredRacquet] = useState<string | null>(null);
  const [colorBy, setColorBy] = useState<keyof Racquet>('brand');
  const [currentView, setCurrentView] = useState(presetViews[0]);
  const [isCalculating, setIsCalculating] = useState(false);
  const [cameraPosition, setCameraPosition] = useState<[number, number, number]>([10, 10, 10]);

  // Calculate PCA coordinates
  const { pcaData, filteredRacquets } = useMemo(() => {
    setIsCalculating(true);

    try {
      const result = calculateRacquetPCA(racquets, {
        features: currentView.features,
        normalize: true,
        dimensions: 3
      });

      const validIndices = new Set<number>();
      racquets.forEach((racquet, index) => {
        const hasAllFeatures = currentView.features.every(feature => {
          const value = racquet[feature];
          return value !== null && value !== undefined && typeof value === 'number' && !isNaN(value);
        });
        if (hasAllFeatures) {
          validIndices.add(index);
        }
      });

      const filtered = racquets.filter((_, index) => validIndices.has(index));

      setIsCalculating(false);
      return {
        pcaData: result,
        filteredRacquets: filtered
      };
    } catch (error) {
      console.error('PCA calculation failed:', error);
      setIsCalculating(false);
      return {
        pcaData: null,
        filteredRacquets: []
      };
    }
  }, [racquets, currentView.features]);

  const handleRacquetClick = useCallback((racquet: Racquet) => {
    setSelectedRacquet(selectedRacquet === racquet.id ? null : racquet.id);
  }, [selectedRacquet]);

  const handleRacquetHover = useCallback((racquet: Racquet | null) => {
    setHoveredRacquet(racquet?.id || null);
  }, []);

  const handleViewChange = useCallback((view: typeof presetViews[0]) => {
    setCurrentView(view);
    setCameraPosition(view.cameraPosition);
  }, []);

  const handleCameraChange = useCallback((_position: THREE.Vector3, _target: THREE.Vector3) => {
    // Optionally track camera changes for view state
  }, []);

  const getSelectedRacquetInfo = useCallback(() => {
    if (!selectedRacquet) return null;
    return filteredRacquets.find(r => r.id === selectedRacquet);
  }, [selectedRacquet, filteredRacquets]);

  const varianceText = useMemo(() => {
    if (!pcaData) return '';
    const total = pcaData.variance.reduce((sum, val) => sum + val, 0);
    const percentages = pcaData.variance.map(val => ((val / total) * 100).toFixed(1));
    return `PC1: ${percentages[0]}%, PC2: ${percentages[1]}%, PC3: ${percentages[2]}%`;
  }, [pcaData]);

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Controls */}
      <Card className="p-6">
        <div className="space-y-4">
          <div>
            <h3 className="text-lg font-semibold mb-3">3D Visualization Controls</h3>
            <div className="grid md:grid-cols-4 gap-3">
              {presetViews.map(view => (
                <Button
                  key={view.id}
                  variant={currentView.id === view.id ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => handleViewChange(view)}
                  className="text-sm h-auto py-3 px-4 flex flex-col items-start"
                >
                  <span className="font-medium">{view.name}</span>
                  <span className="text-xs opacity-70 mt-1">{view.description}</span>
                </Button>
              ))}
            </div>
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-2">Color By</label>
              <Select
                value={colorBy}
                onValueChange={(value) => setColorBy(value as keyof Racquet)}
              >
                {colorByOptions.map(option => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </Select>
              <p className="text-xs text-foreground-muted mt-1">
                {colorByOptions.find(opt => opt.value === colorBy)?.description}
              </p>
            </div>

            <div>
              <label className="block text-sm font-medium mb-2">Variance Explained</label>
              <div className="text-sm font-mono bg-background border rounded px-3 py-2">
                {isCalculating ? 'Calculating...' : varianceText}
              </div>
              <p className="text-xs text-foreground-muted mt-1">
                Principal component variance percentages
              </p>
            </div>
          </div>
        </div>
      </Card>

      {/* 3D Visualization */}
      <Card className="p-6">
        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <h3 className="text-lg font-semibold">{currentView.name}</h3>
            <div className="text-sm text-foreground-muted">
              {filteredRacquets.length} racquets plotted
            </div>
          </div>

          <div className="relative w-full h-[600px] bg-background border rounded-lg overflow-hidden">
            {isCalculating ? (
              <div className="flex items-center justify-center h-full">
                <LoadingSpinner size="lg" />
              </div>
            ) : pcaData && filteredRacquets.length > 0 ? (
              <ThreeScene
                showGrid={true}
                showAxes={true}
                cameraPosition={cameraPosition}
                onCameraChange={handleCameraChange}
              >
                <RacquetPoints3D
                  racquets={filteredRacquets}
                  positions={pcaData.coordinates}
                  selectedRacquet={selectedRacquet}
                  hoveredRacquet={hoveredRacquet}
                  onRacquetClick={handleRacquetClick}
                  onRacquetHover={handleRacquetHover}
                  colorBy={colorBy}
                  scale={1}
                />
              </ThreeScene>
            ) : (
              <div className="flex items-center justify-center h-full text-foreground-muted">
                No data available for visualization
              </div>
            )}
          </div>

          <div className="text-xs text-foreground-muted">
            <p><strong>Controls:</strong> Left click and drag to rotate, right click to pan, scroll to zoom</p>
            <p><strong>Interaction:</strong> Click on points to select, hover for details</p>
          </div>
        </div>
      </Card>

      {/* Selected Racquet Info */}
      {(() => {
        const racquet = getSelectedRacquetInfo();
        if (!racquet) return null;

        return (
          <Card className="p-6">
            <div>
              <h3 className="text-lg font-semibold mb-4">Selected Racquet</h3>
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <h4 className="font-medium text-primary mb-2">{racquet.model}</h4>
                  <p className="text-sm text-foreground-muted mb-3">by {racquet.brand}</p>

                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-sm">Weight:</span>
                      <span className="text-sm font-medium">{racquet.weight_oz} oz</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Head Size:</span>
                      <span className="text-sm font-medium">{racquet.head_size_sq_in} sq in</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Swingweight:</span>
                      <span className="text-sm font-medium">{racquet.swingweight}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Flex:</span>
                      <span className="text-sm font-medium">{racquet.flex}</span>
                    </div>
                  </div>
                </div>

                <div>
                  <h4 className="font-medium mb-3">Performance Ratings</h4>
                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-sm">Power:</span>
                      <span className="text-sm font-medium">{racquet.power_avg}/10</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Control:</span>
                      <span className="text-sm font-medium">{racquet.control_avg}/10</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Maneuverability:</span>
                      <span className="text-sm font-medium">{racquet.maneuverability_avg}/10</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Stability:</span>
                      <span className="text-sm font-medium">{racquet.stability_avg}/10</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-sm">Comfort:</span>
                      <span className="text-sm font-medium">{racquet.comfort_avg}/10</span>
                    </div>
                    <div className="flex justify-between border-t pt-2">
                      <span className="text-sm font-medium">Overall:</span>
                      <span className="text-sm font-bold text-primary">{racquet.overall_avg}/10</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </Card>
        );
      })()}

      {/* Feature Importance */}
      {pcaData && (
        <Card className="p-6">
          <h3 className="text-lg font-semibold mb-4">Feature Importance</h3>
          <div className="grid md:grid-cols-3 gap-4">
            {Object.entries(pcaData.feature_importance)
              .sort(([,a], [,b]) => b - a)
              .slice(0, 6)
              .map(([feature, importance]) => (
                <div key={feature} className="text-center">
                  <div className="text-lg font-bold text-primary">
                    {(importance * 100).toFixed(1)}%
                  </div>
                  <div className="text-sm text-foreground-muted capitalize">
                    {feature.replace(/_/g, ' ')}
                  </div>
                </div>
              ))}
          </div>
        </Card>
      )}
    </div>
  );
}
